package main

import (
    "encoding/json"
    "fmt"
    "log"
    "net/http"
    "strconv"

    "github.com/gorilla/mux"
)

type Player struct {
    ID     int    `json:"id"`
    Name   string `json:"name"`
    Health int    `json:"health"`
    Attack int    `json:"attack"`
    Level  int    `json:"level"`
}

// In-memory "database"
var players = []Player{
    {ID: 1, Name: "Hero", Health: 100, Attack: 20, Level: 5},
    {ID: 2, Name: "Aragorn", Health: 120, Attack: 25, Level: 8},
}
var nextID = 3

func main() {
    r := mux.NewRouter()

    // Routes
    r.HandleFunc("/players", getPlayers).Methods("GET")
    r.HandleFunc("/players", createPlayer).Methods("POST")
    r.HandleFunc("/players/{id}", getPlayer).Methods("GET")
    r.HandleFunc("/players/{id}", updatePlayer).Methods("PUT")
    r.HandleFunc("/players/{id}", deletePlayer).Methods("DELETE")

    fmt.Println("Server running on :8080")
    log.Fatal(http.ListenAndServe(":8080", r))
}

// GET /players
func getPlayers(w http.ResponseWriter, r *http.Request) {
    w.Header().Set("Content-Type", "application/json")
    json.NewEncoder(w).Encode(players)
}

// GET /players/{id}
func getPlayer(w http.ResponseWriter, r *http.Request) {
    vars := mux.Vars(r)
    id, _ := strconv.Atoi(vars["id"])

    for _, p := range players {
        if p.ID == id {
            w.Header().Set("Content-Type", "application/json")
            json.NewEncoder(w).Encode(p)
            return
        }
    }

    w.WriteHeader(http.StatusNotFound)
    json.NewEncoder(w).Encode(map[string]string{"error": "player not found"})
}

// POST /players
func createPlayer(w http.ResponseWriter, r *http.Request) {
    var p Player
    if err := json.NewDecoder(r.Body).Decode(&p); err != nil {
        w.WriteHeader(http.StatusBadRequest)
        json.NewEncoder(w).Encode(map[string]string{"error": "invalid request"})
        return
    }

    p.ID = nextID
    nextID++
    players = append(players, p)

    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(http.StatusCreated)
    json.NewEncoder(w).Encode(p)
}

// PUT /players/{id}
func updatePlayer(w http.ResponseWriter, r *http.Request) {
    vars := mux.Vars(r)
    id, _ := strconv.Atoi(vars["id"])

    var updated Player
    if err := json.NewDecoder(r.Body).Decode(&updated); err != nil {
        w.WriteHeader(http.StatusBadRequest)
        json.NewEncoder(w).Encode(map[string]string{"error": "invalid request"})
        return
    }

    for i, p := range players {
        if p.ID == id {
            updated.ID = id
            players[i] = updated
            w.Header().Set("Content-Type", "application/json")
            json.NewEncoder(w).Encode(updated)
            return
        }
    }

    w.WriteHeader(http.StatusNotFound)
    json.NewEncoder(w).Encode(map[string]string{"error": "player not found"})
}

// DELETE /players/{id}
func deletePlayer(w http.ResponseWriter, r *http.Request) {
    vars := mux.Vars(r)
    id, _ := strconv.Atoi(vars["id"])

    for i, p := range players {
        if p.ID == id {
            players = append(players[:i], players[i+1:]...)
            w.Header().Set("Content-Type", "application/json")
            json.NewEncoder(w).Encode(map[string]string{"message": "player deleted"})
            return
        }
    }

    w.WriteHeader(http.StatusNotFound)
    json.NewEncoder(w).Encode(map[string]string{"error": "player not found"})
}

